@app.put("/api/v1/tasks/{task_id}", response_model=TaskResponse)
async def update_task(
    task_id: uuid.UUID,
    task_update: TaskUpdate,
    current_user: User = Depends(get_current_user),
    db: Session = Depends(get_db)
):
    """Update task with proper authorization and real-time notifications"""

    # Get task with tenant verification through project relationship
    task = db.query(Task).join(Project).filter(
        Task.id == task_id,
        Project.tenant_id == current_user.tenant_id
    ).first()

    if not task:
        raise HTTPException(
            status_code=status.HTTP_404_NOT_FOUND,
            detail="Task not found"
        )

    # Check permissions - users can only edit assigned tasks unless they're manager+
    user_role = UserRole(current_user.role)
    if user_role in [UserRole.VIEWER, UserRole.MEMBER]:
        if task.assignee_id != current_user.id and task.reporter_id != current_user.id:
            raise HTTPException(
                status_code=status.HTTP_403_FORBIDDEN,
                detail="You can only edit tasks assigned to you or created by you"
            )

    # Track changes for real-time notifications
    changes = {}

    # Update fields if provided
    update_data = task_update.dict(exclude_unset=True)
    for field, value in update_data.items():
        if field == "tags" and value is not None:
            # Convert tags list to JSON string for storage
            value = json.dumps(value)

        old_value = getattr(task, field)
        if old_value != value:
            changes[field] = {"old": old_value, "new": value}
            setattr(task, field, value)

    if changes:
        task.updated_at = datetime.utcnow()
        db.commit()
        db.refresh(task)

        # Broadcast real-time update
        await manager.broadcast_to_tenant(
            str(current_user.tenant_id),
            {
                "type": "task_updated",
                "task_id": str(task.id),
                "changes": changes,
                "user": {"id": str(current_user.id), "name": current_user.name},
                "timestamp": datetime.utcnow().isoformat()
            },
            exclude_user=str(current_user.id)
        )

    # Parse tags back to list for response
    if task.tags:
        try:
            task.tags = json.loads(task.tags)
        except json.JSONDecodeError:
            task.tags = []
    else:
        task.tags = []

    return TaskResponse.from_orm(task)

# Secure WebSocket Endpoint Implementation
@app.websocket("/api/v1/ws")
async def websocket_endpoint(websocket: WebSocket, token: str, db: Session = Depends(get_db)):
    """Secure WebSocket endpoint with JWT authentication"""
    try:
        # Verify token before accepting connection
        payload = verify_token(token)
        user_id = payload.get("sub")
        tenant_id = payload.get("tenant_id")

        # Verify user exists and is active
        user = db.query(User).filter(
            User.id == user_id,
            User.tenant_id == tenant_id,
            User.is_active == True
        ).first()

        if not user or user.is_locked():
            await websocket.close(code=1008, reason="Authentication failed")
            return

        # Accept connection and add to manager
        await manager.connect(websocket, user_id, tenant_id)

        try:
            while True:
                # Handle incoming messages
                data = await websocket.receive_text()
                try:
                    message = json.loads(data)
                    await handle_websocket_message(message, user, db)
                except json.JSONDecodeError:
                    await websocket.send_text(json.dumps({
                        "type": "error",
                        "message": "Invalid JSON format"
                    }))

        except WebSocketDisconnect:
            manager.disconnect(user_id, tenant_id)

    except HTTPException:
        await websocket.close(code=1008, reason="Authentication failed")
    except Exception as e:
        logger.error(f"WebSocket error: {e}")
        await websocket.close(code=1011, reason="Internal server error")

async def handle_websocket_message(message: dict, user: User, db: Session):
    """Handle incoming WebSocket messages"""
    message_type = message.get("type")

    if message_type == "typing":
        # Broadcast typing indicator
        task_id = message.get("task_id")
        if task_id:
            await manager.broadcast_to_tenant(
                str(user.tenant_id),
                {
                    "type": "user_typing",
                    "task_id": task_id,
                    "user": {"id": str(user.id), "name": user.name},
                    "timestamp": datetime.utcnow().isoformat()
                },
                exclude_user=str(user.id)
            )

