@app.get("/api/v1/projects", response_model=Dict[str, List[ProjectResponse]])
async def get_projects(
    status: Optional[ProjectStatus] = None,
    current_user: User = Depends(get_current_user),
    db: Session = Depends(get_db)
):
    """Get projects for current tenant with optional filtering"""
    query = db.query(Project).filter(Project.tenant_id == current_user.tenant_id)

    if status:
        query = query.filter(Project.status == status.value)

    projects = query.order_by(Project.created_at.desc()).all()

    return {
        "data": [ProjectResponse.from_orm(project) for project in projects]
    }

@app.post("/api/v1/projects", response_model=ProjectResponse)
async def create_project(
    project_data: ProjectCreate,
    current_user: User = Depends(require_permission(UserRole.MANAGER)),
    db: Session = Depends(get_db)
):
    """Create new project (requires manager role or higher)"""

    # Check tenant project limits
    project_count = db.query(Project).filter(
        Project.tenant_id == current_user.tenant_id,
        Project.status != "archived"
    ).count()

    if project_count >= current_user.tenant.max_projects:
        raise HTTPException(
            status_code=status.HTTP_403_FORBIDDEN,
            detail="Project limit exceeded for your plan"
        )

    project = Project(
        tenant_id=current_user.tenant_id,
        owner_id=current_user.id,
        **project_data.dict()
    )

    db.add(project)
    db.commit()
    db.refresh(project)

    return ProjectResponse.from_orm(project)

